import { useState } from "react";

const useCategories = () => {
  const [categories, setCategories] = useState([
    {
      id: "cat_1",
      title: "Task Status",
      items: [
        { id: 1, name: "Completed" },
        { id: 2, name: "In Progress" },
        { id: 3, name: "Not Started" },
      ],
    },
    {
      id: "cat_2",
      title: "Task Priority",
      items: [
        { id: 1, name: "Extreme" },
        { id: 2, name: "Moderate" },
        { id: 3, name: "Low" },
      ],
    },
  ]);

  const [modalConfig, setModalConfig] = useState({ isOpen: false });

  const updateItems = (categoryId, transformFn) => {
    setCategories((prev) =>
      prev.map((cat) =>
        cat.id === categoryId ? { ...cat, items: transformFn(cat.items) } : cat,
      ),
    );
  };

  const actions = {
    addCategory: (title) => {
      setCategories((prev) => [
        ...prev,
        { id: `cat_${Date.now()}`, title, items: [] },
      ]);
    },
    deleteCategory: (id) => {
      setCategories((prev) => prev.filter((c) => c.id !== id));
    },
    openEdit: (categoryId, item) => {
      setModalConfig({
        isOpen: true,
        type: "edit",
        categoryId,
        item,
        titlePrefix: "Edit",
        titleMain: "Item Name",
        submitLabel: "Update",
        initialValue: item.name,
      });
    },
    openDelete: (categoryId, item) => {
      setModalConfig({
        isOpen: true,
        type: "delete",
        categoryId,
        item,
        titlePrefix: "Delete",
        titleMain: "Item",
        submitLabel: "Delete",
        initialValue: item.name,
        inputLabel: "Are you sure you want to delete?",
      });
    },
    closeModal: () => setModalConfig({ isOpen: false }),
    handleModalSubmit: (newValue) => {
      const { type, categoryId, item } = modalConfig;
      if (type === "edit") {
        updateItems(categoryId, (items) =>
          items.map((i) => (i.id === item.id ? { ...i, name: newValue } : i)),
        );
      } else if (type === "delete") {
        updateItems(categoryId, (items) =>
          items.filter((i) => i.id !== item.id),
        );
      }
      setModalConfig({ isOpen: false });
    },
  };
};
export default useCategories;
